import{_ as i,o as s,c as a,an as t}from"./chunks/framework.CFEZkmYZ.js";const u=JSON.parse('{"title":"Frequently asked questions","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/faq.md","filePath":"getting-started/faq.md","lastUpdated":null}'),o={name:"getting-started/faq.md"};function n(r,e,d,h,l,c){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="faq" tabindex="-1">Frequently asked questions <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;Frequently asked questions {#faq}&quot;">​</a></h1><p>Short answers to the questions this package tends to raise. For a full walkthrough see <a href="/previews/PR235/getting-started/tutorials/composing-distributions#composing-distributions">Composing distributions</a>, and for the verb map see the <a href="/previews/PR235/getting-started/concepts#concepts">Concepts</a> page.</p><h2 id="Where-did-censoring-go?" tabindex="-1">Where did censoring go? <a class="header-anchor" href="#Where-did-censoring-go?" aria-label="Permalink to &quot;Where did censoring go? {#Where-did-censoring-go?}&quot;">​</a></h2><p>ComposedDistributions is the generic composition layer, split out from <a href="https://github.com/EpiAware/CensoredDistributions.jl" target="_blank" rel="noreferrer">CensoredDistributions.jl</a>. It composes any <code>Distributions.jl</code> <code>UnivariateDistribution</code> and adds no censoring of its own. If you need primary-event censoring, interval censoring, or truncation of the observation process, use CensoredDistributions.jl, which builds its censored leaves on top of this composition algebra. Right-truncation of a plain leaf is still available through <code>truncated()</code> from Distributions.jl, since any leaf is an ordinary distribution.</p><h2 id="What-does-rand-of-a-Resolve-or-Compete-node-return?" tabindex="-1">What does <code>rand</code> of a <code>Resolve</code> or <code>Compete</code> node return? <a class="header-anchor" href="#What-does-rand-of-a-Resolve-or-Compete-node-return?" aria-label="Permalink to &quot;What does `rand` of a `Resolve` or `Compete` node return? {#What-does-rand-of-a-Resolve-or-Compete-node-return?}&quot;">​</a></h2><p>A one_of node draws the named event record of the outcome that fired: a <code>NamedTuple</code> keyed by <a href="./@ref"><code>event_names</code></a>, a positional origin slot then one slot per outcome, with the fired outcome&#39;s time present and the others<code>missing</code>. The record names which outcome occurred, so it feeds straight back into<code>logpdf</code>.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ComposedDistributions, Distributions, Random</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> resolve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:death</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:recover</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rand</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Xoshiro</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), node)</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">(event_1 = 0.0, death = 1.8400307468613506, recover = missing)</span></span></code></pre></div><p>For the compact <code>(outcome, time)</code> pair pass <a href="/previews/PR235/lib/internals#Base.rand"><code>rand</code></a><code>(node; outcome = true)</code>; for the marginal time to resolution alone (discarding which outcome fired) sample <a href="/previews/PR235/lib/public#ComposedDistributions.as_mixture"><code>as_mixture</code></a><code>(node)</code>.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rand</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Xoshiro</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), node; outcome </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rand</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Xoshiro</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">as_mixture</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(node))</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">((:death, 1.8400307468613506), 1.8400307468613506)</span></span></code></pre></div><h2 id="I&#39;m-migrating-from-CensoredDistributions&#39;-compose:-what-changed?" tabindex="-1">I&#39;m migrating from CensoredDistributions&#39; <code>compose</code>: what changed? <a class="header-anchor" href="#I&#39;m-migrating-from-CensoredDistributions&#39;-compose:-what-changed?" aria-label="Permalink to &quot;I&#39;m migrating from CensoredDistributions&#39; `compose`: what changed? {#I&#39;m-migrating-from-CensoredDistributions&#39;-compose:-what-changed?}&quot;">​</a></h2><p>CensoredDistributions&#39; <code>compose</code> took varargs pairs, <code>compose(:a =&gt; d1, :b =&gt; d2)</code>. This package&#39;s <code>compose</code> takes a <code>NamedTuple</code>, <code>compose((a = d1, b = d2))</code>, as its primary spelling, because a <code>NamedTuple</code> also carries recursively-nested branch names for tables and matrices, where a flat pairs list cannot. The varargs-pairs spelling still works: <code>compose(:a =&gt; d1, :b =&gt; d2, ...)</code> is a thin convenience method that lowers to the <code>NamedTuple</code> form and returns the identical stack, so existing CensoredDistributions-style call sites keep working unmodified. Prefer the <code>NamedTuple</code> form in new code.</p><h2 id="How-do-I-get-the-total-delay-distribution-of-a-chain?" tabindex="-1">How do I get the total-delay distribution of a chain? <a class="header-anchor" href="#How-do-I-get-the-total-delay-distribution-of-a-chain?" aria-label="Permalink to &quot;How do I get the total-delay distribution of a chain? {#How-do-I-get-the-total-delay-distribution-of-a-chain?}&quot;">​</a></h2><p>A <a href="/previews/PR235/lib/public#ComposedDistributions.Sequential"><code>Sequential</code></a> chain models each step separately; to collapse it to the single distribution of its origin-to-final gap, use <a href="/previews/PR235/lib/public#ComposedDistributions.observed_distribution"><code>observed_distribution</code></a>, which convolves the steps into one delay. For two standalone delays that are not part of a tree, <a href="/previews/PR235/lib/public#ConvolvedDistributions.convolved"><code>convolved</code></a> gives their sum <code>X + Y</code> directly. See <a href="/previews/PR235/getting-started/tutorials/linear-chain#linear-chain">Delay chains and the linear chain trick</a> for a worked example.</p><h2 id="How-do-I-fix-a-parameter-across-branches?" tabindex="-1">How do I fix a parameter across branches? <a class="header-anchor" href="#How-do-I-fix-a-parameter-across-branches?" aria-label="Permalink to &quot;How do I fix a parameter across branches? {#How-do-I-fix-a-parameter-across-branches?}&quot;">​</a></h2><p>Use <a href="/previews/PR235/lib/public#ComposedDistributions.shared"><code>shared</code></a> or <a href="/previews/PR235/lib/public#ComposedDistributions.tie"><code>tie</code></a> to make several leaves one free parameter: <code>shared</code> tags a leaf where it is built, <code>tie</code> walks an assembled tree to named leaves and ties them. Either way <a href="/previews/PR235/lib/public#ComposedDistributions.params_table"><code>params_table</code></a> then inventories the tied occurrences once under the shared tag rather than as separate parameters. See <a href="/previews/PR235/getting-started/tutorials/composing-distributions#composing-distributions">Composing distributions</a> for a worked example.</p><h2 id="Why-is-my-logpdf-Inf?" tabindex="-1">Why is my <code>logpdf</code> <code>-Inf</code>? <a class="header-anchor" href="#Why-is-my-logpdf-Inf?" aria-label="Permalink to &quot;Why is my `logpdf` `-Inf`? {#Why-is-my-logpdf-Inf?}&quot;">​</a></h2><p>A composed <code>logpdf</code> is <code>-Inf</code> when a value falls outside a leaf&#39;s support. The commonest cause is a negative or zero value scored against a positive-support delay, such as a <code>Gamma</code> or <code>LogNormal</code>. When scoring a whole record, check that every value sits in its own leaf&#39;s support and that the record is laid out in the tree&#39;s event order (see <a href="/previews/PR235/lib/public#ComposedDistributions.event_names"><code>event_names</code></a>); a value in the wrong slot can land outside the leaf that scores it.</p><h2 id="How-do-I-fit-a-composed-distribution-to-data?" tabindex="-1">How do I fit a composed distribution to data? <a class="header-anchor" href="#How-do-I-fit-a-composed-distribution-to-data?" aria-label="Permalink to &quot;How do I fit a composed distribution to data? {#How-do-I-fit-a-composed-distribution-to-data?}&quot;">​</a></h2><p>Mark the parameters to estimate by building a leaf with <a href="/previews/PR235/lib/public#ComposedDistributions.uncertain"><code>uncertain</code></a>, or promote a leaf/subtree/whole tree already in place with <a href="/previews/PR235/lib/public#ComposedDistributions.uncertain"><code>uncertain</code></a><code>(tree, ...)</code> / <code>uncertain(tree)</code>, then package the tree and data into a log-density with <a href="./@ref"><code>as_logdensity</code></a>, or wrap it as a <code>DynamicPPL</code> model with <a href="/previews/PR235/lib/public#ComposedDistributions.as_turing"><code>as_turing</code></a> for direct sampling with Turing.jl. See <a href="/previews/PR235/getting-started/inference#inference">Fitting a composed distribution</a> for the full pipeline.</p><h2 id="Is-a-composed-distribution-really-a-Distribution?" tabindex="-1">Is a composed distribution really a <code>Distribution</code>? <a class="header-anchor" href="#Is-a-composed-distribution-really-a-Distribution?" aria-label="Permalink to &quot;Is a composed distribution really a `Distribution`? {#Is-a-composed-distribution-really-a-Distribution?}&quot;">​</a></h2><p>Yes. Every composer subtypes <code>Distributions.Distribution</code>, so <code>logpdf</code>, <code>rand</code>, <code>mean</code>, <code>var</code>, <code>cdf</code> (where defined) and the rest of the interface work unchanged, and a composed object drops into any code that expects a distribution.</p>',23)])])}const k=i(o,[["render",n]]);export{u as __pageData,k as default};
